4	export const POST = withGated("gate.submit", async (req) => {
5	  const body = (await req.json()) as {
6	    conclusionId?: string;
7	    kind?: string;
8	    notes?: string;
9	  };
10	  if (!body.conclusionId || !body.kind) {
11	    return NextResponse.json(
12	      { ok: false, error: "conclusionId and kind are required" },
13	      { status: 400 },
14	    );
15	  }
16	
17	  const { spawn } = await import("child_process");
18	  const result = await new Promise<{ ok: boolean; data?: unknown; error?: string }>((resolve) => {
19	    const proc = spawn("python", [
20	      "-m", "noosphere", "rigor-gate", "submit",
21	      `--kind=${body.kind}`,
22	      `--conclusion-id=${body.conclusionId}`,
23	      ...(body.notes ? [`--notes=${body.notes}`] : []),
24	    ]);
25	    let stdout = "";
26	    let stderr = "";
27	    proc.stdout.on("data", (d: Buffer) => { stdout += d.toString(); });
28	    proc.stderr.on("data", (d: Buffer) => { stderr += d.toString(); });
29	    proc.on("close", (code) => {
30	      if (code === 0) {
31	        try {
32	          resolve({ ok: true, data: JSON.parse(stdout) });
33	        } catch {
34	          resolve({ ok: true, data: stdout });
35	        }
36	      } else {
37	        resolve({ ok: false, error: stderr || "Gate submission failed" });
38	      }
39	    });
40	    proc.on("error", () => resolve({ ok: false, error: "Failed to spawn process" }));
41	  });
42	
43	  return NextResponse.json(result, { status: result.ok ? 200 : 500 });
44	});
