144	function spawnPython(
145	  args: string[],
146	): Promise<{ code: number; stdout: string; stderr: string }> {
147	  return new Promise((resolve) => {
148	    const proc = spawn("python", ["-m", "noosphere", ...args]);
149	    let stdout = "";
150	    let stderr = "";
151	    proc.stdout.on("data", (d: Buffer) => {
152	      stdout += d.toString();
153	    });
154	    proc.stderr.on("data", (d: Buffer) => {
155	      stderr += d.toString();
156	    });
157	    proc.on("close", (code) =>
158	      resolve({ code: code ?? 1, stdout, stderr }),
159	    );
160	    proc.on("error", () =>
161	      resolve({ code: 1, stdout, stderr: "spawn failed" }),
162	    );
163	  });
164	}
