166	export async function submitToRigorGate(
167	  kind: string,
168	  founderName: string,
169	): Promise<{ approved: boolean; ledgerEntryId: string; reason?: string }> {
170	  const { code, stdout, stderr } = await spawnPython([
171	    "rigor-gate",
172	    "submit",
173	    `--kind=${kind}`,
174	    `--founder=${founderName}`,
175	  ]);
176	
177	  if (code === 0) {
178	    try {
179	      const parsed = JSON.parse(stdout) as { ledger_entry_id?: string };
180	      return {
181	        approved: true,
182	        ledgerEntryId: parsed.ledger_entry_id || `gate-${Date.now()}`,
183	      };
184	    } catch {
185	      return { approved: true, ledgerEntryId: `gate-${Date.now()}` };
186	    }
187	  }
188	
189	  if (process.env.NODE_ENV !== "production") {
190	    return { approved: true, ledgerEntryId: `dev-gate-${Date.now()}` };
191	  }
192	
193	  return {
194	    approved: false,
195	    ledgerEntryId: "",
196	    reason: stderr || "Rigor gate rejected",
197	  };
198	}
