205	export function withGated(kind: string, handler: RouteHandler): RouteHandler {
206	  return async (req, ctx) => {
207	    const founder = await getFounder();
208	    if (!founder) {
209	      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
210	    }
211	
212	    const gate = await submitToRigorGate(kind, founder.name);
213	    if (!gate.approved) {
214	      return NextResponse.json(
215	        { ok: false, error: "Rigor gate rejected", reason: gate.reason },
216	        { status: 403 },
217	      );
218	    }
219	
220	    const response = await handler(req, ctx);
221	    const body = await response.json();
222	    return NextResponse.json(
223	      { ...body, ledgerEntryId: gate.ledgerEntryId },
224	      { status: response.status },
225	    );
226	  };
227	}
