286	export async function fetchCascade(
287	  conclusionId: string,
288	): Promise<CascadeNode[]> {
289	  const rows = await safeQuery(
290	    Prisma.sql`SELECT id, conclusion_id, parent_id, kind, label, confidence FROM cascade_node WHERE conclusion_id = ${conclusionId} ORDER BY id`,
291	  );
292	  const flat = rows.map((r) => ({
293	    id: String(r.id),
294	    conclusionId: String(r.conclusion_id),
295	    parentId: r.parent_id ? String(r.parent_id) : null,
296	    kind: String(r.kind ?? ""),
297	    label: String(r.label ?? ""),
298	    confidence: Number(r.confidence ?? 0),
299	    children: [] as CascadeNode[],
300	  }));
301	  const byId = new Map(flat.map((n) => [n.id, n]));
302	  const roots: CascadeNode[] = [];
303	  for (const node of flat) {
304	    if (node.parentId && byId.has(node.parentId)) {
305	      byId.get(node.parentId)!.children.push(node);
306	    } else {
307	      roots.push(node);
308	    }
309	  }
310	  return roots;
311	}
