492	export function toCSV(rows: Record<string, unknown>[]): string {
493	  if (rows.length === 0) return "";
494	  const headers = Object.keys(rows[0]);
495	  const lines = [headers.join(",")];
496	  for (const row of rows) {
497	    lines.push(
498	      headers
499	        .map((h) => {
500	          const v = row[h];
501	          const s =
502	            typeof v === "object" ? JSON.stringify(v) : String(v ?? "");
503	          return s.includes(",") || s.includes('"')
504	            ? `"${s.replace(/"/g, '""')}"`
505	            : s;
506	        })
507	        .join(","),
508	    );
509	  }
510	  return lines.join("\n");
511	}
