#!/usr/bin/env python3
"""CI lint: fail if any module calls a ported method directly instead of via REGISTRY.get()."""
from __future__ import annotations

import argparse
import ast
import sys
from pathlib import Path

REPO_ROOT = Path(__file__).resolve().parent.parent


def _populate_registry() -> None:
    import importlib

    methods_dir = REPO_ROOT / "noosphere" / "noosphere" / "methods"
    for py in sorted(methods_dir.glob("*.py")):
        if py.name.startswith("_") or py.name == "__init__.py":
            continue
        try:
            importlib.import_module(f"noosphere.methods.{py.stem}")
        except Exception:
            pass


def _build_target_set() -> set[str]:
    from noosphere.methods._registry import REGISTRY

    targets: set[str] = set()

    for spec in REGISTRY.list():
        impl = spec.implementation
        targets.add(f"{impl.module}.{impl.fn_name}")

    legacy_dir = REPO_ROOT / "noosphere" / "noosphere" / "methods" / "_legacy"
    for py in sorted(legacy_dir.glob("*.py")):
        if py.name.startswith("_") or py.name == "__init__.py":
            continue
        mod_fqn = f"noosphere.methods._legacy.{py.stem}"
        try:
            tree = ast.parse(py.read_text())
        except Exception:
            continue
        for node in ast.iter_child_nodes(tree):
            if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef, ast.ClassDef)):
                if not node.name.startswith("_"):
                    targets.add(f"{mod_fqn}.{node.name}")

    return targets


def _resolve_attr_chain(node: ast.AST) -> list[str] | None:
    if isinstance(node, ast.Name):
        return [node.id]
    if isinstance(node, ast.Attribute):
        base = _resolve_attr_chain(node.value)
        if base is not None:
            return [*base, node.attr]
    return None


def _build_import_map(tree: ast.Module) -> dict[str, str]:
    imap: dict[str, str] = {}
    for node in ast.walk(tree):
        if isinstance(node, ast.Import):
            for alias in node.names:
                if alias.asname:
                    imap[alias.asname] = alias.name
                else:
                    top = alias.name.split(".")[0]
                    imap.setdefault(top, top)
        elif isinstance(node, ast.ImportFrom) and node.module:
            for alias in node.names:
                local = alias.asname or alias.name
                imap[local] = f"{node.module}.{alias.name}"
    return imap


def _scan_file(
    filepath: Path, targets: set[str], methods_dir: Path
) -> list[str]:
    try:
        filepath.resolve().relative_to(methods_dir.resolve())
        return []
    except ValueError:
        pass

    try:
        tree = ast.parse(filepath.read_text(), filename=str(filepath))
    except Exception:
        return []

    imap = _build_import_map(tree)
    violations: list[str] = []

    for node in ast.walk(tree):
        if not isinstance(node, ast.Call):
            continue
        chain = _resolve_attr_chain(node.func)
        if not chain:
            continue
        head = chain[0]
        if head not in imap:
            continue
        fqn = imap[head] + ("." + ".".join(chain[1:]) if len(chain) > 1 else "")
        if fqn in targets:
            violations.append(
                f"{filepath}:{node.lineno} calls ported fn {fqn} directly"
                f" — use REGISTRY.get()"
            )

    return violations


def main() -> int:
    parser = argparse.ArgumentParser(
        description="Check that ported methods are called through REGISTRY",
    )
    parser.add_argument("--scan-dir", action="append", default=None)
    args = parser.parse_args()

    sys.path.insert(0, str(REPO_ROOT / "noosphere"))
    _populate_registry()
    targets = _build_target_set()

    if not targets:
        print("No ported methods found in registry — nothing to check.")
        return 0

    scan_dirs = args.scan_dir or [str(REPO_ROOT / "noosphere" / "noosphere")]
    methods_dir = REPO_ROOT / "noosphere" / "noosphere" / "methods"
    violations: list[str] = []

    for scan_dir in scan_dirs:
        for py_file in sorted(Path(scan_dir).rglob("*.py")):
            if "__pycache__" in py_file.parts:
                continue
            violations.extend(_scan_file(py_file, targets, methods_dir))

    if violations:
        for v in violations:
            print(v)
        print(f"\n{len(violations)} violation(s) found.")
        return 1

    print("No bypass violations found.")
    return 0


if __name__ == "__main__":
    sys.exit(main())

#!/usr/bin/env python3
"""AST-walk publication-handler modules and fail if any lack @gated."""

from __future__ import annotations

import ast
import os
import sys
from pathlib import Path

DEFAULT_HANDLER_PATHS = [
    "founder-portal/src/app/api/",
    "researcher_api/researcher_api/routes/",
]


def _handler_paths() -> list[str]:
    env = os.environ.get("GATED_HANDLER_PATHS")
    if env:
        return [p.strip() for p in env.split(",") if p.strip()]
    return DEFAULT_HANDLER_PATHS


def _python_files(root: str) -> list[Path]:
    base = Path(root)
    if not base.exists():
        return []
    return sorted(base.rglob("*.py"))


def _has_gated_decorator(node: ast.FunctionDef | ast.AsyncFunctionDef) -> bool:
    for dec in node.decorator_list:
        if isinstance(dec, ast.Call):
            func = dec.func
            if isinstance(func, ast.Name) and func.id == "gated":
                return True
            if isinstance(func, ast.Attribute) and func.attr == "gated":
                return True
        elif isinstance(dec, ast.Name) and dec.id == "gated":
            return True
        elif isinstance(dec, ast.Attribute) and dec.attr == "gated":
            return True
    return False


def _is_publication_handler(node: ast.FunctionDef | ast.AsyncFunctionDef) -> bool:
    """Heuristic: functions that look like they write to a public store."""
    name = node.name.lower()
    publish_keywords = ("publish", "create_public", "post_public", "write_public")
    return any(kw in name for kw in publish_keywords)


def check_file(filepath: Path) -> list[str]:
    try:
        source = filepath.read_text()
        tree = ast.parse(source, filename=str(filepath))
    except (SyntaxError, UnicodeDecodeError):
        return []

    issues: list[str] = []
    for node in ast.walk(tree):
        if isinstance(node, (ast.FunctionDef, ast.AsyncFunctionDef)):
            if _is_publication_handler(node) and not _has_gated_decorator(node):
                issues.append(
                    f"{filepath}:{node.lineno} — {node.name}() lacks @gated decorator"
                )
    return issues


def main() -> int:
    paths = _handler_paths()
    all_issues: list[str] = []

    for handler_path in paths:
        for py_file in _python_files(handler_path):
            all_issues.extend(check_file(py_file))

    if all_issues:
        print("FAIL: publication handlers missing @gated decorator:")
        for issue in all_issues:
            print(f"  {issue}")
        return 1

    print("OK: all publication handlers have @gated decorator")
    return 0


if __name__ == "__main__":
    sys.exit(main())

